import{db}from"./firebase-config.js";import{collection,addDoc,serverTimestamp}from"https://www.gstatic.com/firebasejs/11.4.0/firebase-firestore.js";document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("contact-form"),t=document.getElementById("contact-name"),s=document.getElementById("contact-email"),a=document.getElementById("contact-message"),n=document.getElementById("contact-submit"),i=document.getElementById("contact-toast");e&&e.addEventListener("submit",async r=>{r.preventDefault(),n.innerHTML='Transmitting... <i class="fas fa-spinner fa-spin ml-2"></i>',n.disabled=!0,i.classList.add("hidden");try{await addDoc(collection(db,"contacts"),{name:t.value.trim(),email:s.value.trim(),message:a.value.trim(),timestamp:serverTimestamp(),status:"unread"}),e.reset(),i.innerHTML='<i class="fas fa-check-circle mr-2"></i> Message transmitted successfully. We will respond shortly.',i.className="text-sm font-bold p-3 rounded bg-green-500/10 text-green-400 border border-green-500/30",i.classList.remove("hidden")}catch(e){console.error("Error adding document: ",e),i.innerHTML='<i class="fas fa-exclamation-triangle mr-2"></i> Transmission failed. Please contact us directly via email.',i.className="text-sm font-bold p-3 rounded bg-red-500/10 text-red-400 border border-red-500/30",i.classList.remove("hidden")}finally{n.innerHTML='Initiate Transmission <i class="fas fa-paper-plane ml-2"></i>',n.disabled=!1}})});